public interface ITicketState {
  string Handle();
}

public class OpenState : ITicketState {
  public string Handle() => "Open";
}

public class ClosedState : ITicketState {
  public string Handle() => "Closed";
}

public class TicketContext {
  private ITicketState _state = new OpenState();
  public void SetState(ITicketState state) { _state = state; }
  public string Status() => _state.Handle();
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Context_ChangesBehavior_WhenStateChanges() {
  var ticket = new TicketContext();
  Assert.AreEqual("Open", ticket.Status());

  ticket.SetState(new ClosedState());
  Assert.AreEqual("Closed", ticket.Status());
}

[TestMethod]
public void Context_DelegatesToCurrentState() {
  var ticket = new TicketContext();
  Assert.AreEqual("Open", ticket.Status());
}
